import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}
// DO NOT EDIT types below — auto-generated from the data contract





// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  city: string;
  temperatureText: string;
  condition: string;
  conditionIcon: string;
  humidityText: string;
  windText: string;
  forecast: Array<{ day: string; icon: string; highText: string; lowText: string }>;
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  // add your state, effects, and wire hook logic here

  // DO NOT EDIT wire hooks below — auto-generated from the data contract

  const unitLabel = props.unit || '';
  const normalizedCondition = props.condition.trim().toLowerCase();
  const temperatureText = `${props.temperature}°${unitLabel}`;
  const humidityText = `${props.humidity}%`;
  const windText = `${props.windSpeed} km/h`;
  const conditionIcon = normalizedCondition.includes('thunder') || normalizedCondition.includes('storm')
    ? '⛈️'
    : normalizedCondition.includes('snow') || normalizedCondition.includes('sleet') || normalizedCondition.includes('blizzard')
      ? '❄️'
      : normalizedCondition.includes('rain') || normalizedCondition.includes('drizzle') || normalizedCondition.includes('shower')
        ? '🌧️'
        : normalizedCondition.includes('partly cloudy') || normalizedCondition.includes('cloud') || normalizedCondition.includes('overcast')
          ? '☁️'
          : normalizedCondition.includes('sun') || normalizedCondition.includes('clear')
            ? '☀️'
            : '🌡️';
  const slicedForecast = props.forecast.slice(0, 5);
  const forecast = Array.from({ length: 5 }, (_, index) => {
    const item = slicedForecast[index];
    return {
      day: item?.day || `Day ${index + 1}` ,
      icon: item?.icon || '—',
      highText: item?.high !== undefined ? `${item.high}°${unitLabel}` : '--',
      lowText: item?.low !== undefined ? `${item.low}°${unitLabel}` : '--',
    };
  });
  return {
    city: props.city,
    temperatureText,
    condition: props.condition,
    conditionIcon,
    humidityText,
    windText,
    forecast,
  };
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  // add any UI-only state here (tabs, accordions, scroll position, etc.)

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card
          padding="var(--ggui-spacing-6)"
          radius="lg"
          shadow="md"
          border
        >
          <Stack gap="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-2)">
              <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Weather
              </Text>
              <Heading level={2}>{props.city}</Heading>
            </Stack>

            <Row gap="var(--ggui-spacing-6)" align="center" justify="between" wrap>
              <Stack gap="var(--ggui-spacing-2)">
                <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                  {props.temperatureText}
                </Text>
                <Row gap="var(--ggui-spacing-2)" align="center">
                  <Text size="2xl" is="span" aria-label={`${props.condition} icon`}>
                    {props.conditionIcon}
                  </Text>
                  <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {props.condition}
                  </Text>
                </Row>
              </Stack>

              <Stack gap="var(--ggui-spacing-2)">
                <Row gap="var(--ggui-spacing-2)" align="center">
                  <Icon name="droplets" size={18} color="var(--ggui-color-primary-600, #0284c7)" />
                  <Text variant="label">Humidity</Text>
                  <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">{props.humidityText}</Text>
                </Row>
                <Row gap="var(--ggui-spacing-2)" align="center">
                  <Icon name="wind" size={18} color="var(--ggui-color-primary-600, #0284c7)" />
                  <Text variant="label">Wind</Text>
                  <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">{props.windText}</Text>
                </Row>
              </Stack>
            </Row>

            <Divider margin="var(--ggui-spacing-2)" />

            <Stack gap="var(--ggui-spacing-3)">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                5-Day Forecast
              </Text>
              <Row gap="var(--ggui-spacing-2)" wrap>
                {props.forecast.map((item, index) => (
                  <Card
                    key={`${item.day}-${index}`}
                    padding="var(--ggui-spacing-4)"
                    radius="md"
                    shadow="none"
                    border
                  >
                    <Stack gap="var(--ggui-spacing-1)" align="center">
                      {item.day && (
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          {item.day}
                        </Text>
                      )}
                      {item.icon && (
                        <Text size="xl" is="span" aria-label={item.day ? `Forecast icon for ${item.day}` : 'Forecast icon'}>
                          {item.icon}
                        </Text>
                      )}
                      {item.highText && <Text variant="bodySmall" weight="semibold">{item.highText}</Text>}
                      {item.lowText && (
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          {item.lowText}
                        </Text>
                      )}
                    </Stack>
                  </Card>
                ))}
              </Row>
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

// DO NOT EDIT render — it connects Controller to View
export default function render(props: Props) {
  const viewProps = ComponentController(props);
  return <ComponentView {...viewProps} />;
}

