// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}
// DO NOT EDIT types below — auto-generated from the data contract

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  currentStep: number;
  totalSteps: number;
  name: string;
  email: string;
  satisfaction: string;
  selectedFeatures: string[];
  comments: string;
  nameError: string;
  emailError: string;
  canGoNext: boolean;
  canSubmit: boolean;
  satisfactionOptions: { value: string; label: string }[];
  featureOptions: string[];
  reviewData: ActionSubmitPayload;
  onNameChange: (value: string) => void;
  onEmailChange: (value: string) => void;
  onSatisfactionChange: (value: string) => void;
  onToggleFeature: (feature: string, checked: boolean) => void;
  onCommentsChange: (value: string) => void;
  onBack: () => void;
  onNext: () => void;
  onSubmit: () => void;
}

const TOTAL_STEPS = 5;

const isValidEmail = (value: string): boolean => {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(value.trim());
};

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [touched, setTouched] = useState({ name: false, email: false });

  // DO NOT EDIT wire hooks below — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const nameError = touched.name && !name.trim() ? 'Name is required' : '';
  const emailError = touched.email
    ? !email.trim()
      ? 'Email is required'
      : !isValidEmail(email)
        ? 'Please enter a valid email address'
        : ''
    : '';

  const satisfactionOptions = useMemo(
    () => props.satisfactionLabels.map((label, index) => ({ value: String(index + 1), label })),
    [props.satisfactionLabels]
  );

  const isStepValid = useMemo(() => {
    if (currentStep === 1) return !!name.trim() && !!email.trim() && isValidEmail(email);
    if (currentStep === 2) return !!satisfaction;
    if (currentStep === 3) return true;
    if (currentStep === 4) return comments.length <= 500;
    return true;
  }, [currentStep, name, email, satisfaction, comments]);

  const isFormValidForSubmit = useMemo(
    () => !!name.trim() && !!email.trim() && isValidEmail(email) && !!satisfaction && comments.length <= 500,
    [name, email, satisfaction, comments]
  );

  const canGoNext = currentStep < TOTAL_STEPS && isStepValid;
  const canSubmit = currentStep === TOTAL_STEPS && isFormValidForSubmit;

  const reviewData = useMemo<ActionSubmitPayload>(() => ({
    name: name.trim(),
    email: email.trim(),
    satisfaction: satisfaction ? Number(satisfaction) : 0,
    features: selectedFeatures,
    comments,
  }), [name, email, satisfaction, selectedFeatures, comments]);

  const onNameChange = useCallback((value: string) => {
    setName(value);
    if (!touched.name) setTouched((prev) => ({ ...prev, name: true }));
  }, [touched.name]);

  const onEmailChange = useCallback((value: string) => {
    setEmail(value);
    if (!touched.email) setTouched((prev) => ({ ...prev, email: true }));
  }, [touched.email]);

  const onSatisfactionChange = useCallback((value: string) => setSatisfaction(value), []);

  const onToggleFeature = useCallback((feature: string, checked: boolean) => {
    setSelectedFeatures((prev) =>
      checked ? [...prev, feature] : prev.filter((item) => item !== feature)
    );
  }, []);

  const onCommentsChange = useCallback((value: string) => setComments(value), []);

  const onBack = useCallback(() => {
    setCurrentStep((prev) => Math.max(1, prev - 1));
  }, []);

  const onNext = useCallback(() => {
    if (currentStep === 1) setTouched({ name: true, email: true });
    if (isStepValid) setCurrentStep((prev) => Math.min(TOTAL_STEPS, prev + 1));
  }, [currentStep, isStepValid]);

  const onSubmit = useCallback(() => {
    submit(reviewData);
  }, [submit, reviewData]);

  return {
    currentStep,
    totalSteps: TOTAL_STEPS,
    name,
    email,
    satisfaction,
    selectedFeatures,
    comments,
    nameError,
    emailError,
    canGoNext,
    canSubmit,
    satisfactionOptions,
    featureOptions: props.featureOptions,
    reviewData,
    onNameChange,
    onEmailChange,
    onSatisfactionChange,
    onToggleFeature,
    onCommentsChange,
    onBack,
    onNext,
    onSubmit,
  };
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  const satisfactionLabel = props.satisfaction
    ? props.satisfactionOptions.find((option) => option.value === props.satisfaction)?.label || 'Not selected'
    : 'Not selected';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={2}>Survey Form</Heading>
          <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {props.currentStep} of {props.totalSteps}
          </Text>
          <Progress value={props.currentStep} max={props.totalSteps} />
        </Stack>

        <Card padding="var(--ggui-spacing-6)" shadow="sm" border>
          <Stack gap="var(--ggui-spacing-4)">
            {props.currentStep === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Input
                  label="Name"
                  value={props.name}
                  onChange={props.onNameChange}
                  required
                  error={props.nameError}
                />
                <Input
                  label="Email"
                  type="email"
                  value={props.email}
                  onChange={props.onEmailChange}
                  required
                  error={props.emailError}
                />
              </Stack>
            )}

            {props.currentStep === 2 && (
              <RadioGroup
                label="How satisfied are you?"
                value={props.satisfaction}
                onChange={props.onSatisfactionChange}
                options={props.satisfactionOptions}
                direction="vertical"
              />
            )}

            {props.currentStep === 3 && (
              <Stack gap="var(--ggui-spacing-3)">
                <Text variant="label">Which features interest you?</Text>
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={props.selectedFeatures.includes(feature)}
                    onChange={(checked) => props.onToggleFeature(feature, checked)}
                  />
                ))}
              </Stack>
            )}

            {props.currentStep === 4 && (
              <TextArea
                label="Additional comments (optional)"
                value={props.comments}
                onChange={props.onCommentsChange}
                maxLength={500}
                showCount
                rows={6}
                helperText="Share anything else you'd like us to know."
              />
            )}

            {props.currentStep === 5 && (
              <Stack gap="var(--ggui-spacing-3)">
                <Heading level={4}>Review your answers</Heading>
                <Text><Text is="span" weight="semibold">Name:</Text> {props.reviewData.name}</Text>
                <Text><Text is="span" weight="semibold">Email:</Text> {props.reviewData.email}</Text>
                <Text><Text is="span" weight="semibold">Satisfaction:</Text> {satisfactionLabel}</Text>
                <Text>
                  <Text is="span" weight="semibold">Features:</Text>{' '}
                  {props.reviewData.features.length ? props.reviewData.features.join(', ') : 'None selected'}
                </Text>
                <Text>
                  <Text is="span" weight="semibold">Comments:</Text>{' '}
                  {props.reviewData.comments || 'No comments provided'}
                </Text>
              </Stack>
            )}
          </Stack>
        </Card>

        <Row gap="var(--ggui-spacing-2)">
          <Button variant="ghost" onClick={props.onBack} disabled={props.currentStep === 1}>
            Back
          </Button>
          <Spacer size="flex" />
          {props.currentStep < props.totalSteps && (
            <Button variant="primary" onClick={props.onNext} disabled={!props.canGoNext}>
              Next
            </Button>
          )}
          {props.currentStep === props.totalSteps && (
            <Button variant="primary" onClick={props.onSubmit} disabled={!props.canSubmit}>
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>

  );
}

// DO NOT EDIT render — it connects Controller to View
export default function render(props: Props) {
  const viewProps = ComponentController(props);
  return <ComponentView {...viewProps} />;
}

