// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}
// DO NOT EDIT types below — auto-generated from the data contract

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; dueDate?: string; clientRequestId?: string; clientTempId?: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string; clientRequestId?: string; clientTempId?: string } };




// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  columns: Array<{ id: string; name: string }>;
  tasksByColumn: Record<string, Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string }>>;
  totalTasks: number;
  completedTasks: number;
  streamMessage: string;
  addStateByColumn: Record<string, { title: string; priority: 'low' | 'medium' | 'high'; assignee: string; dueDate: string; open: boolean }>;
  editingTaskId: string | null;
  editingTitle: string;
  setEditingTitle: (value: string) => void;
  onStartEdit: (taskId: string, currentTitle: string) => void;
  onSaveEdit: (taskId: string) => void;
  onCancelEdit: () => void;
  onMoveTask: (taskId: string, toColumn: string) => void;
  onOpenAdd: (columnId: string) => void;
  onCancelAdd: (columnId: string) => void;
  onAddTitleChange: (columnId: string, value: string) => void;
  onAddPriorityChange: (columnId: string, value: 'low' | 'medium' | 'high') => void;
  onAddAssigneeChange: (columnId: string, value: string) => void;
  onAddDueDateChange: (columnId: string, value: string) => void;
  onCreateTask: (columnId: string) => void;
}


type TaskItem = {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  assignee: string;
  column: string;
  dueDate?: string;
};

const PRIORITY_OPTIONS = [
  { value: 'low', label: 'Low' },
  { value: 'medium', label: 'Medium' },
  { value: 'high', label: 'High' },
];

function normalizeColumns(columns: Props['columns']) {
  const defaults = [
    { id: 'todo', name: 'To Do' },
    { id: 'in-progress', name: 'In Progress' },
    { id: 'done', name: 'Done' },
  ];
  if (!columns?.length) return defaults;
  return columns.map((c, i) => ({
    id: c.id || defaults[i]?.id || `column-${i + 1}`,
    name: c.name || defaults[i]?.name || `Column ${i + 1}`
  }));
}

function normalizeTasks(tasks: Props['tasks'], firstColumnId: string): TaskItem[] {
  return (tasks || []).map((t, i) => ({
    id: t.id || `task-${i + 1}`,
    title: t.title || 'Untitled task',
    priority: t.priority || 'medium',
    assignee: t.assignee || 'NA',
    column: t.column || firstColumnId,
    dueDate: t.dueDate,
  }));
}

function getPriorityVariant(priority: 'low' | 'medium' | 'high'): 'success' | 'warning' | 'error' {
  if (priority === 'low') return 'success';
  if (priority === 'high') return 'error';
  return 'warning';
}

function ComponentController(props: Props): ViewProps {
  // DO NOT EDIT wire hooks below — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const columns = useMemo(() => normalizeColumns(props.columns), [props.columns]);
  const firstColumnId = columns[0]?.id || 'todo';
  const [tasks, setTasks] = useState<TaskItem[]>(() => normalizeTasks(props.tasks, firstColumnId));
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [addStateByColumn, setAddStateByColumn] = useState<Record<string, { title: string; priority: 'low' | 'medium' | 'high'; assignee: string; dueDate: string; open: boolean }>>(() =>
    columns.reduce((acc, col) => {
      acc[col.id] = { title: '', priority: 'medium', assignee: '', dueDate: '', open: false };
      return acc;
    }, {} as Record<string, { title: string; priority: 'low' | 'medium' | 'high'; assignee: string; dueDate: string; open: boolean }>)
  );


  useEffect(() => {
    setTasks((prev) => {
      const incoming = normalizeTasks(props.tasks, firstColumnId);
      const localById = new Map(prev.map((t) => [t.id, t]));
      const incomingIds = new Set(incoming.map((t) => t.id));
      const merged = incoming.map((t) => {
        const local = localById.get(t.id);
        if (!local) return t;
        if (editingTaskId === t.id) {
          return { ...t, title: local.title };
        }
        return { ...local, ...t };
      });
      prev.forEach((t) => {
        if (!incomingIds.has(t.id)) merged.push(t);
      });
      return merged;
    });
  }, [props.tasks, firstColumnId, editingTaskId]);
  useEffect(() => {
    const latest = taskChanged.latest;
    if (!latest?.task?.id || !latest.action) return;
    const incoming: TaskItem = {
      id: latest.task.id,
      title: latest.task.title || 'Untitled task',
      priority: latest.task.priority || 'medium',
      assignee: latest.task.assignee || 'NA',
      column: latest.task.column || firstColumnId,
      dueDate: latest.task.dueDate,
    };
    setTasks((prev) => {
      if (latest.action === 'delete') return prev.filter((t) => t.id !== incoming.id);
      const byIdIdx = prev.findIndex((t) => t.id === incoming.id);
      const byTempIdx = latest.task?.clientTempId ? prev.findIndex((t) => t.id === latest.task?.clientTempId) : -1;
      const byRequestIdx = latest.task?.clientRequestId
        ? prev.findIndex((t) => t.id.includes(`req-${latest.task?.clientRequestId}`))
        : -1;
      const idx = byIdIdx !== -1 ? byIdIdx : byTempIdx !== -1 ? byTempIdx : byRequestIdx;
      if (idx === -1) return [...prev, incoming];
      const copy = [...prev];
      if (editingTaskId === incoming.id || editingTaskId === copy[idx].id) {
        copy[idx] = {
          ...copy[idx],
          title: editingTitle,
          column: incoming.column,
          priority: incoming.priority,
          assignee: incoming.assignee,
          dueDate: incoming.dueDate,
          id: incoming.id,
        };
        return copy;
      }
      copy[idx] = { ...copy[idx], ...incoming, id: incoming.id };
      return copy;
    });
  }, [taskChanged.latest, firstColumnId, editingTaskId, editingTitle]);

  const tasksByColumn = useMemo(() => {
    return columns.reduce((acc, c) => {
      acc[c.id] = tasks.filter((t) => t.column === c.id);
      return acc;
    }, {} as Record<string, TaskItem[]>);
  }, [tasks, columns]);

  const totalTasks = tasks.length;
  const doneColumnId = useMemo(() => {
    const exact = columns.find((c) => c.id.toLowerCase() === 'done');
    if (exact) return exact.id;
    const byName = columns.find((c) => c.name.toLowerCase().includes('done') || c.name.toLowerCase().includes('complete'));
    return byName?.id || columns[columns.length - 1]?.id || firstColumnId;
  }, [columns, firstColumnId]);
  const completedTasks = tasksByColumn[doneColumnId]?.length || 0;

  const onMoveTask = useCallback((taskId: string, toColumn: string) => {
    setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, column: toColumn } : t)));
    taskUpdate({ action: 'move', taskId, data: { column: toColumn } });
  }, [taskUpdate]);

  const onStartEdit = useCallback((taskId: string, currentTitle: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(currentTitle);
  }, []);

  const onSaveEdit = useCallback((taskId: string) => {
    const nextTitle = editingTitle.trim();
    if (!nextTitle) return;
    const existing = tasks.find((t) => t.id === taskId);
    const nextColumn = existing?.column || firstColumnId;
    setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, title: nextTitle } : t)));
    setEditingTaskId(null);
    setEditingTitle('');
    taskUpdate({ action: 'edit', taskId, data: { column: nextColumn, title: nextTitle, priority: existing?.priority || 'medium', assignee: existing?.assignee || 'NA', dueDate: existing?.dueDate || '' } });
  }, [editingTitle, taskUpdate, tasks, firstColumnId]);

  const onCancelEdit = useCallback(() => {
    setEditingTaskId(null);
    setEditingTitle('');
  }, []);

  const onOpenAdd = useCallback((columnId: string) => {
    setAddStateByColumn((prev) => ({ ...prev, [columnId]: { ...prev[columnId], open: true } }));
  }, []);

  const onCancelAdd = useCallback((columnId: string) => {
    setAddStateByColumn((prev) => ({ ...prev, [columnId]: { title: '', priority: 'medium', assignee: '', dueDate: '', open: false } }));
  }, []);

  const onAddTitleChange = useCallback((columnId: string, value: string) => {
    setAddStateByColumn((prev) => ({ ...prev, [columnId]: { ...prev[columnId], title: value } }));
  }, []);

  const onAddPriorityChange = useCallback((columnId: string, value: 'low' | 'medium' | 'high') => {
    setAddStateByColumn((prev) => ({ ...prev, [columnId]: { ...prev[columnId], priority: value } }));
  }, []);

  const onAddAssigneeChange = useCallback((columnId: string, value: string) => {
    setAddStateByColumn((prev) => ({ ...prev, [columnId]: { ...prev[columnId], assignee: value } }));
  }, []);

  const onAddDueDateChange = useCallback((columnId: string, value: string) => {
    setAddStateByColumn((prev) => ({ ...prev, [columnId]: { ...prev[columnId], dueDate: value } }));
  }, []);

  const onCreateTask = useCallback((columnId: string) => {
    const state = addStateByColumn[columnId];
    const title = state?.title?.trim();
    if (!title) return;
    const clientRequestId = `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    const taskId = `task-temp-req-${clientRequestId}`;
    const nextTask: TaskItem = {
      id: taskId,
      title,
      priority: state.priority || 'medium',
      assignee: state.assignee?.trim() || 'ME',
      column: columnId || firstColumnId,
      dueDate: state.dueDate || undefined,
    };
    setTasks((prev) => [...prev, nextTask]);
    setAddStateByColumn((prev) => ({ ...prev, [columnId]: { title: '', priority: 'medium', assignee: '', dueDate: '', open: false } }));
    taskUpdate({
      action: 'create',
      taskId: nextTask.id,
      data: {
        column: nextTask.column,
        title: nextTask.title,
        priority: nextTask.priority,
        assignee: nextTask.assignee,
        dueDate: nextTask.dueDate || '',
        clientRequestId,
        clientTempId: nextTask.id,
      },
    });
  }, [addStateByColumn, taskUpdate, firstColumnId]);

  const streamMessage = taskChanged.latest?.action ? `Live update: ${taskChanged.latest.action}` : 'No live updates yet';

  return {
    columns,
    tasksByColumn,
    totalTasks,
    completedTasks,
    streamMessage,
    addStateByColumn,
    editingTaskId,
    editingTitle,
    setEditingTitle,
    onStartEdit,
    onSaveEdit,
    onCancelEdit,
    onMoveTask,
    onOpenAdd,
    onCancelAdd,
    onAddPriorityChange,
    onAddAssigneeChange,
    onAddDueDateChange,
    onAddTitleChange,
    onCreateTask,
  };
}
