  'var(--ggui-color-error-200, #fecaca)',
  'var(--ggui-color-primary-50, #f0f9ff)',
  'var(--ggui-color-container, #ede9fe)',
];

function normalizeCategory(category?: string): string {
  return (category ?? '').trim().toLowerCase().replace(/[-\s]+/g, ' ');
}

function getCategoryColor(category?: string): string {
  const normalized = normalizeCategory(category);
  if (!normalized) return 'var(--ggui-color-surfaceVariant, #f4f4f5)';
  let hash = 0;
  for (let i = 0; i < normalized.length; i += 1) hash = (hash * 31 + normalized.charCodeAt(i)) >>> 0;
  return CATEGORY_PALETTE[hash % CATEGORY_PALETTE.length];
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number } | null>(null);

  // DO NOT EDIT wire hooks below — auto-generated from the data contract

  const filteredElements = useMemo(() => {
    const query = searchQuery.trim().toLowerCase();
    if (!query) return props.elements;
    return props.elements.filter((element) => {
      const name = element.name?.toLowerCase() ?? '';
      const symbol = element.symbol?.toLowerCase() ?? '';
      return name.includes(query) || symbol.includes(query);
    });
  }, [props.elements, searchQuery]);

  const categories = useMemo(() => {
    const unique = new Set<string>();
    props.elements.forEach((element) => {
      if (element.category) unique.add(element.category);
    });
    return Array.from(unique).sort((a, b) => a.localeCompare(b));
  }, [props.elements]);

  const onSelectElement = useCallback((element: { atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }) => {
    setSelectedElement(element);
  }, []);

  return {
    searchQuery,
    setSearchQuery,
    filteredElements,
    selectedElement,
    onSelectElement,
    categories,
    getCategoryColor,
  };
}

