  return Math.max(1, Math.min(5, Math.round(value)));
}

function toSpecPairs(items: unknown[]): Array<{ key: string; value: string }> {
  return items.map((item, index) => {
    if (item && typeof item === 'object') {
      const record = item as Record<string, unknown>;
      const key = String(record.key ?? record.name ?? record.label ?? `Spec ${index + 1}`);
      const value = String(record.value ?? record.detail ?? record.description ?? '-');
      return { key, value };
    }
    return { key: `Spec ${index + 1}`, value: String(item) };
  });
}

function toReviews(items: unknown[]): Array<{ author: string; rating: number; text: string; date: string }> {
  return items.map((item, index) => {
    if (item && typeof item === 'object') {
      const record = item as Record<string, unknown>;
      return {
        author: String(record.author ?? record.name ?? `Reviewer ${index + 1}`),
        rating: clampRating(Number(record.rating ?? 5)),
        text: String(record.text ?? record.comment ?? ''),
        date: String(record.date ?? record.createdAt ?? ''),
      };
    }
    return { author: `Reviewer ${index + 1}`, rating: 5, text: String(item), date: '' };
  });
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }
  const productId = props.product.id ?? '';
  const stock = Math.max(0, props.product.stock ?? 0);
  const [quantity, setQuantity] = useState(1);

  useEffect(() => {
    setQuantity((prev) => {
      if (stock <= 0) return 1;
      return Math.min(Math.max(1, prev), stock);
    });
  }, [stock]);

  const onIncrement = useCallback(() => {
    setQuantity((prev) => Math.min(stock || 1, prev + 1));
  }, [stock]);

  const onDecrement = useCallback(() => {
    setQuantity((prev) => Math.max(1, prev - 1));
  }, []);

  const onAddToCart = useCallback(() => {
    if (!productId || stock <= 0) return;
    addToCart({ productId, quantity });
  }, [addToCart, productId, quantity, stock]);

  const rating = clampRating(props.product.rating ?? 1);
  const reviewCount = props.product.reviewCount ?? 0;
  const stockLabel = stock <= 0 ? 'Out of Stock' : stock > 5 ? 'In Stock' : 'Low Stock';
  const stockVariant = stock <= 0 ? 'error' : stock > 5 ? 'success' : 'warning';

  return {
    productId,
    name: props.product.name ?? 'Unnamed Product',
    priceLabel: formatPrice(props.product.price ?? 0, props.product.currency ?? ''),
    rating,
    reviewCount,
    stock,
    stockLabel,
    stockVariant,
    description: props.product.description ?? '',
    specifications: toSpecPairs(props.product.specifications ?? []),
    reviews: toReviews(props.product.reviews ?? []),
    quantity,
    canIncrease: stock > 0 && quantity < stock,
    canDecrease: quantity > 1,
    canAddToCart: stock > 0 && Boolean(productId),
    onIncrement,
    onDecrement,
    onAddToCart,
  };
}

