// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  title: string;
  participantCount: number;
  currentUser: string;
  messages: Array<{ sender: string; text: string; timestamp: string }>;
  typingSender: string | null;
  draft: string;
  onDraftChange: (value: string) => void;
  onSend: () => void;
}

function getTimestampMs(timestamp: string) {
  const value = new Date(timestamp).getTime();
  return Number.isNaN(value) ? 0 : value;
}

function sortMessages(messages: Array<{ sender: string; text: string; timestamp: string }>) {
  return [...messages].sort((a, b) => getTimestampMs(a.timestamp) - getTimestampMs(b.timestamp));
}

function normalizeMessage(msg: { sender?: string; text?: string; timestamp?: string }) {
  return {
    sender: msg.sender || 'Unknown',
    text: msg.text || '',
    timestamp: msg.timestamp || new Date().toISOString(),
  };
}

function formatTime(value: string) {
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [messagesState, setMessagesState] = useState<Array<{ sender: string; text: string; timestamp: string }>>(
    () => sortMessages(props.messages.map(normalizeMessage)),
  );
  const [draft, setDraft] = useState('');

  // DO NOT EDIT wire hooks below — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  useEffect(() => {
    setMessagesState(sortMessages(props.messages.map(normalizeMessage)));
  }, [props.messages]);

  useEffect(() => {
    if (!message.latest) return;
    setMessagesState((prev) => sortMessages([...prev, normalizeMessage(message.latest)]));
  }, [message.latest]);

  const onSend = useCallback(() => {
    const text = draft.trim();
    if (!text) return;
    const timestamp = new Date().toISOString();
    sendMessage({ text, timestamp });
    setMessagesState((prev) => sortMessages([...prev, { sender: props.currentUser, text, timestamp }]));
    setDraft('');
  }, [draft, sendMessage, props.currentUser]);

  const typingSender = useMemo(() => {
    if (!typing.latest?.active || !typing.latest.sender || typing.latest.sender === props.currentUser) return null;
    return typing.latest.sender;
  }, [typing.latest, props.currentUser]);

  return {
    title: props.title,
    participantCount: props.participantCount,
    currentUser: props.currentUser,
    messages: messagesState,
    typingSender,
    draft,
    onDraftChange: setDraft,
    onSend,
  };
}

