    const node = messagesScrollRef.current;
    if (!node) return;
    const threshold = 48;
    shouldAutoScrollRef.current = node.scrollTop + node.clientHeight >= node.scrollHeight - threshold;
  }, []);

  useEffect(() => {
    if (!shouldAutoScrollRef.current) return;
    endRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [props.messages.length]);
  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
