            >
              <Stack gap="var(--ggui-spacing-2)">
                {props.messages.map((msg, index) => {
                  const isOwn = msg.sender === props.currentUser;
                  const previous = index > 0 ? props.messages[index - 1] : null;
                  const showSender = !previous || previous.sender !== msg.sender;
                  return (
                    <Row key={`${msg.timestamp}-${index}`} justify={isOwn ? 'end' : 'start'}>
                      <Box
                        background={
                          isOwn
                            ? 'var(--ggui-color-primary-600, #0284c7)'
                            : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                        }
                        padding="var(--ggui-spacing-2)"
                        borderRadius="var(--ggui-shape-radius-md, 8px)"
                      >
                        <Stack gap="var(--ggui-spacing-1)">
                          {showSender && (
                            <Text
                              variant="caption"
                              weight="semibold"
                              color={
                                isOwn
                                  ? 'var(--ggui-color-surface, #ffffff)'
                                  : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                              }
                            >
                              {msg.sender}
                            </Text>
