                                ? 'var(--ggui-color-primary-100, #e0f2fe)'
                                : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                            }
                            align={isOwn ? 'right' : 'left'}
                          >
                            {formatTime(msg.timestamp)}
                          </Text>
                        </Stack>
                      </Box>
                    </Row>
                  );
                })}
                <div ref={endRef} />
              </Stack>
            </Box>

            <Row gap="var(--ggui-spacing-2)" align="end">
              <Box style={{ flex: 1 }}>
                <Input
                  label="Message"
                  placeholder="Type a message..."
                  value={props.draft}
                  onChange={props.onDraftChange}
