    changePercent: number;
    flash: boolean;
  }>;
  marketStatus: 'open' | 'closed' | 'pre-market' | 'after-hours' | 'unknown';
  lastUpdatedLabel: string;
  streamCount: number;
}

function formatTimestamp(date: Date): string {
  return date.toLocaleTimeString();
}

function normalizeStock(stock: Props['stocks'][number]) {
  return {
    symbol: stock.symbol ?? '—',
    name: stock.name ?? 'Unknown Company',
    price: stock.price ?? 0,
    change: stock.change ?? 0,
    changePercent: stock.changePercent ?? 0,
    flash: false,
  };
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [stocks, setStocks] = useState(() => props.stocks.map(normalizeStock));
  const [lastUpdatedAt, setLastUpdatedAt] = useState<Date>(new Date());

  // DO NOT EDIT wire hooks below — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  useEffect(() => {
    setStocks(props.stocks.map(normalizeStock));
  }, [props.stocks]);

  useEffect(() => {
    if (!priceUpdate.latest?.symbol) return;
    const incoming = priceUpdate.latest;
    setStocks((prev) => {
      const existingIndex = prev.findIndex((stock) => stock.symbol === incoming.symbol);
      if (existingIndex === -1) {
        return [
          ...prev,
          {
            symbol: incoming.symbol ?? '—',
            name: 'Unknown Company',
            price: incoming.price ?? 0,
            change: incoming.change ?? 0,
            changePercent: incoming.changePercent ?? 0,
            flash: true,
          },
        ];
      }
      return prev.map((stock) => {
        if (stock.symbol !== incoming.symbol) return stock;
        return {
          ...stock,
          price: incoming.price ?? stock.price,
          change: incoming.change ?? stock.change,
          changePercent: incoming.changePercent ?? stock.changePercent,
          flash: true,
        };
      });
    });
    setLastUpdatedAt(new Date());
  }, [priceUpdate.latest]);

  useEffect(() => {
    const timer = setInterval(() => {
      setLastUpdatedAt(new Date());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (!stocks.some((stock) => stock.flash)) return;
    const flashTimer = setTimeout(() => {
      setStocks((prev) => prev.map((stock) => (stock.flash ? { ...stock, flash: false } : stock)));
    }, 450);
    return () => clearTimeout(flashTimer);
  }, [stocks]);

  const statusValue = marketStatus.latest?.status ?? 'unknown';

  return {
    stocks,
    marketStatus: statusValue,
    lastUpdatedLabel: formatTimestamp(lastUpdatedAt),
    streamCount: priceUpdate.all.length,
  };
}

