// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}
// DO NOT EDIT types below — auto-generated from the data contract

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





// Helper constants/functions
const DEFAULT_AVATARS = ['😀', '🚀', '🎨', '🧠'];
const DEFAULT_ROLES = ['Developer', 'Designer', 'Manager', 'Other'];

function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim());
}

// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  step: number;
  totalSteps: number;
  progressValue: number;
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
  avatarOptions: string[];
  roleOptions: string[];
  emailError: string;
  canGoNext: boolean;
  isFirstStep: boolean;
  isLastStep: boolean;
  setName: (value: string) => void;
  setEmail: (value: string) => void;
  setAvatar: (value: string) => void;
  setRole: (value: string) => void;
  setEmailNotifications: (value: boolean) => void;
  setTheme: (value: boolean) => void;
  goBack: () => void;
  goNext: () => void;
  completeSetup: () => void;
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [step, setStep] = useState(1);
  const initialProfile = props.initialProfile ?? {};
  const safeAvatarOptions = props.avatarOptions ?? [];
  const safeRoleOptions = props.roleOptions ?? [];
  const [name, setName] = useState(initialProfile.name ?? '');
  const [email, setEmail] = useState(initialProfile.email ?? '');
  const [avatar, setAvatar] = useState(initialProfile.avatar ?? (safeAvatarOptions[0] ?? DEFAULT_AVATARS[0]));
  const [role, setRole] = useState(initialProfile.role ?? 'Other');
  const [emailNotifications, setEmailNotifications] = useState(initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState((initialProfile.theme ?? 'light') === 'dark');

  // DO NOT EDIT wire hooks below — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  const totalSteps = 3;
  const avatarOptions = safeAvatarOptions.length ? safeAvatarOptions : DEFAULT_AVATARS;
  const roleOptions = safeRoleOptions.length ? safeRoleOptions : DEFAULT_ROLES;
  const emailError = email.trim().length > 0 && !isValidEmail(email) ? 'Please enter a valid email address.' : '';
  const stepOneValid = name.trim().length > 0 && email.trim().length > 0 && emailError === '' && avatar.trim().length > 0;
  const canGoNext = step === 1 ? stepOneValid : step < totalSteps;
  const progressValue = (step / totalSteps) * 100;
  const isFirstStep = step === 1;
  const isLastStep = step === totalSteps;

  const goBack = useCallback(() => setStep((s) => Math.max(1, s - 1)), []);
  const goNext = useCallback(() => {
    if (step === 1 && !stepOneValid) return;
    setStep((s) => Math.min(totalSteps, s + 1));
  }, [step, stepOneValid]);

  const completeSetup = useCallback(() => {
    const payload: ActionCompletePayload = {
      name: name.trim(),
      email: email.trim(),
      avatar,
      role: role || 'Other',
      emailNotifications,
      theme: theme ? 'dark' : 'light',
    };
    complete(payload);
  }, [name, email, avatar, role, emailNotifications, theme, complete]);

  return {
    step,
    totalSteps,
    progressValue,
    name,
    email,
    avatar,
    role,
    emailNotifications,
    theme: theme ? 'dark' : 'light',
    avatarOptions,
    roleOptions,
    emailError,
    canGoNext,
    isFirstStep,
    isLastStep,
    setName,
    setEmail,
    setAvatar,
    setRole,
    setEmailNotifications,
    setTheme,
    goBack,
    goNext,
    completeSetup,
  };
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  const stepTitle = props.step === 1 ? 'Profile Setup' : props.step === 2 ? 'Preferences' : 'Review & Confirm';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={2}>Onboarding Wizard</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {props.step} of {props.totalSteps}: {stepTitle}
          </Text>
          <Progress value={props.progressValue} max={100} size="md" />
        </Stack>

        <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg">
          <Box
            style={{
              animation: 'ggui-fadeIn 200ms ease-out',
            }}
          >
            {props.step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Input label="Name" value={props.name} onChange={props.setName} required helperText="Enter your full name" />
                <Input
                  label="Email"
                  type="email"
                  value={props.email}
                  onChange={props.setEmail}
                  required
                  error={props.emailError}
                  helperText="We'll use this for account updates"
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label">Choose Avatar</Text>
                  <Row gap="var(--ggui-spacing-2)">
                    {props.avatarOptions.slice(0, 4).map((option) => (
                      <Button
                        key={option}
                        variant={props.avatar === option ? 'primary' : 'outline'}
                        onClick={() => props.setAvatar(option)}
                        aria-label={`Select avatar ${option}`}
                      >
                        {option}
                      </Button>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {props.step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Select
                  label="Role"
                  value={props.role}
                  onChange={props.setRole}
                  options={props.roleOptions.map((r) => ({ value: r, label: r }))}
                  placeholder="Select your role"
                />
                <Toggle
                  label="Email notifications"
                  checked={props.emailNotifications}
                  onChange={props.setEmailNotifications}
                />
                <Toggle
                  label="Dark theme"
                  checked={props.theme === 'dark'}
                  onChange={props.setTheme}
                />
              </Stack>
            )}

            {props.step === 3 && (
              <Stack gap="var(--ggui-spacing-3)">
                <Heading level={4}>Review your setup</Heading>
                <Text>Name: {props.name || '—'}</Text>
                <Text>Email: {props.email || '—'}</Text>
                <Text>Avatar: {props.avatar || '—'}</Text>
                <Text>Role: {props.role || 'Other'}</Text>
                <Text>Email Notifications: {props.emailNotifications ? 'On' : 'Off'}</Text>
                <Text>Theme: {props.theme}</Text>
              </Stack>
            )}
          </Box>
        </Card>

        <Row gap="var(--ggui-spacing-2)">
          {!props.isFirstStep && (
            <Button variant="ghost" onClick={props.goBack}>
              Go Back
            </Button>
          )}
          <Spacer size="flex" />
          {!props.isLastStep ? (
            <Button variant="primary" onClick={props.goNext} disabled={!props.canGoNext}>
              Next
            </Button>
          ) : (
            <Button variant="primary" onClick={props.completeSetup}>
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>

  );
}

// DO NOT EDIT render — it connects Controller to View
export default function render(props: Props) {
  const viewProps = ComponentController(props);
  return <ComponentView {...viewProps} />;
}
